  1→/**
  2→ * Contract API Client
  3→ *
  4→ * TypeScript client for Contract API with fetch wrapper.
  5→ * Provides typed methods for CRUD operations on contracts.
  6→ */
  7→
  8→import type {
  9→  ContractData,
 10→  ContractListParams,
 11→  ContractCreateInput,
 12→  ContractUpdateInput,
 13→  ContractVersionCreateInput,
 14→  ContractSignerCreateInput,
 15→  DealConvertInput,
 16→  ApiListResponse,
 17→  ApiResponse,
 18→  ApiClientConfig,
 19→} from './types';
 20→import { ApiClientError, parseApiError, parseJson } from './shared';
 21→
 22→export { ApiClientError } from './shared';
 23→
 24→/**
 25→ * Default base URL for API requests
 26→ */
 27→const DEFAULT_BASE_URL = '/api';
 28→
 29→/**
 30→ * Contract API Client
 31→ */
 32→export class ContractApiClient {
 33→  private baseUrl: string;
 34→  private fetchFn: typeof globalThis.fetch;
 35→  private defaultHeaders: Record<string, string>;
 36→
 37→  constructor(config: ApiClientConfig = {}) {
 38→    this.baseUrl = config.baseUrl ?? DEFAULT_BASE_URL;
 39→    this.fetchFn = config.fetch ?? fetch;
 40→    this.defaultHeaders = {
 41→      'Content-Type': 'application/json',
 42→      ...config.headers,
 43→    };
 44→  }
 45→
 46→  private url(path: string, params?: Record<string, string | undefined>): string {
 47→    const fullUrl = `${this.baseUrl}${path}`;
 48→    if (params) {
 49→      const searchParams = new URLSearchParams();
 50→      for (const [key, value] of Object.entries(params)) {
 51→        if (value !== undefined) {
 52→          searchParams.append(key, value);
 53→        }
 54→      }
 55→      const queryString = searchParams.toString();
 56→      if (queryString) return `${fullUrl}?${queryString}`;
 57→    }
 58→    return fullUrl;
 59→  }
 60→
 61→  async getContracts(params?: ContractListParams): Promise<ApiListResponse<ContractData>> {
 62→    const response = await this.fetchFn(
 63→      this.url('/contracts', {
 64→        status: params?.status,
 65→        contactId: params?.contactId,
 66→        dealId: params?.dealId,
 67→      }),
 68→      { headers: this.defaultHeaders }
 69→    );
 70→    if (!response.ok) return parseApiError(response);
 71→    return parseJson<ApiListResponse<ContractData>>(response);
 72→  }
 73→
 74→  async getContract(id: string): Promise<ApiResponse<ContractData>> {
 75→    if (!id) throw new ApiClientError(400, 'Validation failed', 'id is required');
 76→    const response = await this.fetchFn(this.url(`/contracts/${id}`), {
 77→      headers: this.defaultHeaders,
 78→    });
 79→    if (!response.ok) return parseApiError(response);
 80→    return parseJson<ApiResponse<ContractData>>(response);
 81→  }
 82→
 83→  async createContract(data: ContractCreateInput): Promise<ApiResponse<ContractData>> {
 84→    const response = await this.fetchFn(this.url('/contracts'), {
 85→      method: 'POST',
 86→      headers: this.defaultHeaders,
 87→      body: JSON.stringify(data),
 88→    });
 89→    if (!response.ok) return parseApiError(response);
 90→    return parseJson<ApiResponse<ContractData>>(response);
 91→  }
 92→
 93→  async updateContract(
 94→    id: string,
 95→    data: ContractUpdateInput
 96→  ): Promise<ApiResponse<ContractData>> {
 97→    if (!id) throw new ApiClientError(400, 'Validation failed', 'id is required');
 98→    const response = await this.fetchFn(this.url(`/contracts/${id}`), {
 99→      method: 'PATCH',
100→      headers: this.defaultHeaders,
101→      body: JSON.stringify(data),
102→    });
103→    if (!response.ok) return parseApiError(response);
104→    return parseJson<ApiResponse<ContractData>>(response);
105→  }
106→
107→  async deleteContract(id: string): Promise<ApiResponse<ContractData>> {
108→    if (!id) throw new ApiClientError(400, 'Validation failed', 'id is required');
109→    const response = await this.fetchFn(this.url(`/contracts/${id}`), {
110→      method: 'DELETE',
111→      headers: this.defaultHeaders,
112→    });
113→    if (!response.ok) return parseApiError(response);
114→    return parseJson<ApiResponse<ContractData>>(response);
115→  }
116→
117→  async getVersions(id: string): Promise<ApiListResponse<any>> {
118→    const response = await this.fetchFn(this.url(`/contracts/${id}/versions`), {
119→      headers: this.defaultHeaders,
120→    });
121→    if (!response.ok) return parseApiError(response);
122→    return parseJson<ApiListResponse<any>>(response);
123→  }
124→
125→  async addVersion(id: string, data: ContractVersionCreateInput): Promise<ApiResponse<any>> {
126→    const response = await this.fetchFn(this.url(`/contracts/${id}/versions`), {
127→      method: 'POST',
128→      headers: this.defaultHeaders,
129→      body: JSON.stringify(data),
130→    });
131→    if (!response.ok) return parseApiError(response);
132→    return parseJson<ApiResponse<any>>(response);
133→  }
134→
135→  async getSigners(id: string): Promise<ApiListResponse<any>> {
136→    const response = await this.fetchFn(this.url(`/contracts/${id}/signers`), {
137→      headers: this.defaultHeaders,
138→    });
139→    if (!response.ok) return parseApiError(response);
140→    return parseJson<ApiListResponse<any>>(response);
141→  }
142→
143→  async addSigner(id: string, data: ContractSignerCreateInput): Promise<ApiResponse<any>> {
144→    const response = await this.fetchFn(this.url(`/contracts/${id}/signers`), {
145→      method: 'POST',
146→      headers: this.defaultHeaders,
147→      body: JSON.stringify(data),
148→    });
149→    if (!response.ok) return parseApiError(response);
150→    return parseJson<ApiResponse<any>>(response);
151→  }
152→
153→  async convertDeal(id: string, data: DealConvertInput): Promise<ApiResponse<{ contract: ContractData; deal: DealData }>> {
154→    const response = await this.fetchFn(this.url(`/deals/${id}/convert`), {
155→      method: 'POST',
156→      headers: this.defaultHeaders,
157→      body: JSON.stringify(data),
158→    });
159→    if (!response.ok) return parseApiError(response);
160→    return parseJson<ApiResponse<{ contract: ContractData; deal: DealData }>>(response);
161→  }
162→}
163→
164→export const contractsApi = new ContractApiClient();
165→
166→export const {
167→  getContracts,
168→  getContract,
169→  createContract,
170→  updateContract,
171→  deleteContract,
172→  getVersions,
173→  addVersion,
174→  getSigners,
175→  addSigner,
176→  convertDeal,
177→} = contractsApi;
178→
179→export default contractsApi;
